import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from 'src/app/core/services/auth.service';
import { Chart } from 'chart.js/auto';
import { FormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css'],
})
export class DashboardComponent implements OnInit {

  profile: any;
  aiPlan: any;
  additionalInfos: any[] = [];
  medicineName: string = '';
  medicineTime: string = '';
  bpRecords: any[] = [];
  bpDates: string[] = [];
  currentBP: any[] = [];
  previousBP: any[] = [];
  filteredBP: any[] = [];
  systolic: number[] = [];
  diastolic: number[] = [];
  pulse: number[] = [];
  showAll: boolean = false;

  reminders: { id: number; name: string; time: string; editing: boolean }[] = [];

  constructor(private router: Router, private authService: AuthService) { }

  ngOnInit() {
    this.loadAdditionalInfo();
    this.loadBP();

    this.authService.getProfile().subscribe({
      next: (res: any) => {
        this.profile = res;

        // Calculate health score AFTER profile loads
        this.profile.healthScore = this.calculateHealthScore();

        // Wait for DOM to render
        setTimeout(() => {
          this.createChart();
        }, 100);
      },
      error: (err) => {
        console.log(err);
      }

    });

    this.authService.getAdditionalInfo().subscribe({
      next: (res: any) => {
        this.additionalInfos = res;
      },
      error: (err) => {
        console.log("Additional info load error", err);
      }
    });

    // Load reminders
    this.authService.getReminders().subscribe((data: any) => {
      this.reminders = data;
    });
  }

  loadAdditionalInfo() {
    this.authService.getAdditionalInfo().subscribe((res: any) => {
      this.additionalInfos = res || [];
    });
  }
  // HEALTH SCORE
  calculateHealthScore(): number {

    if (!this.profile) return 0;

    let score = 0;
    const bmi = this.profile.bmi;
    const diseases = this.profile.knownDiseases || [];

    if (bmi >= 18.5 && bmi < 25) {
      score = 90;
    } else if (bmi >= 25 && bmi < 30) {
      score = 70;
    } else if (bmi < 18.5) {
      score = 65;
    } else {
      score = 50;
    }

    score -= diseases.length * 10;

    if (score < 20) score = 20;

    return score;
  }

  // CHART
  createChart() {

    if (!this.profile?.bmi) return;

    const canvas = document.getElementById("bmiChart") as HTMLCanvasElement;

    if (!canvas) return;

    new Chart(canvas, {
      type: 'bar',
      data: {
        labels: ['Your BMI'],
        datasets: [{
          label: 'BMI',
          data: [this.profile.bmi]
        }]
      }
    });
  }

  // AI PLAN
  getPlan() {
    this.authService.getAIPlan(this.profile).subscribe({
      next: (res: any) => {
        console.log("PLAN:", res);
        this.aiPlan = res;
      },
      error: (err) => {
        console.error(err);
      }
    });
  }
  // REMINDERS
  setReminder() {
    if (!this.medicineName || !this.medicineTime) return;

    this.authService.addReminder({
      medicineName: this.medicineName,
      time: this.medicineTime
    }).subscribe((newReminder: any) => {
      this.reminders.push(newReminder);
      this.medicineName = '';
      this.medicineTime = '';
    });
  }
  deleteReminder(index: number) {
    const reminder = this.reminders[index];

    this.authService.deleteReminder(reminder.id).subscribe(() => {
      this.reminders.splice(index, 1);
    });
  }

  editReminder(index: number) {
    this.reminders[index].editing = true;
  }

  saveReminder(index: number) {
    const reminder = this.reminders[index];

    this.authService.updateReminder(reminder.id, {
      name: reminder.name,
      time: reminder.time
    }).subscribe(() => {
      reminder.editing = false;
    });
  }
  cancelEdit(index: number) {
    this.reminders[index].editing = false;
  }
  addBP() {
    const data = {
      systolic: this.systolic,
      diastolic: this.diastolic,
      pulse: this.pulse
    };

    this.authService.addBloodPressure(data).subscribe(() => {
      this.systolic;
      this.diastolic;
      this.pulse;
      this.loadBP();
    });
  }

  loadBP() {
    this.authService.getBloodPressure().subscribe((data: any) => {
      this.bpRecords = data;
      this.processBPData(); 
      console.log("All BP:", this.bpRecords);
console.log("Current Week:", this.currentBP);
    });
  }

  getBPStatus(s: number, d: number): string {

    if (s >= 180 || d > 120) {
      return "Hypertensive Crisis";
    }
    if (s >= 140 || d >= 90) {
      return "Stage 2 Hypertension";
    }
    if (s >= 130 || d >= 80) {
      return "Stage 1 Hypertension";
    }
    if (s >= 120 && d < 80) {
      return "Elevated";
    }
    return "Normal";
  }

  getBPClass(s: number, d: number): string {
    if (s >= 180 || d >= 120) {
      return "crisis";
    }
    if (s >= 140 || d >= 90) {
      return "stage2";
    }
    if (s >= 130 || d >= 80) {
      return "stage1";
    }
    if (s >= 120 && d < 80) {
      return "elevated";
    }
    return "normal";
  }

  applyFilter() {
    if (this.showAll) {
      this.filteredBP = this.bpRecords;
    } else {
      this.filteredBP = this.bpRecords.slice(0, 7); // Last 7 records
    }
  }
  toggleView() {
    this.showAll = !this.showAll;
    this.applyFilter();
  }

  processBPData() {

  if (!this.bpRecords || this.bpRecords.length === 0) {
    this.currentBP = [];
    this.previousBP = [];
    return;
  }

  // First 7 latest records = current week
  this.currentBP = this.bpRecords.slice(0, 7);

  const older = this.bpRecords.slice(7);

  const grouped: any = {};

  older.forEach(bp => {
    const date = new Date(bp.recorded_at);
    const weekStart = new Date(date);
    weekStart.setDate(date.getDate() - date.getDay());

    const key = weekStart.toDateString();

    if (!grouped[key]) {
      grouped[key] = [];
    }

    grouped[key].push(bp);
  });

  this.previousBP = Object.keys(grouped).map(key => ({
    weekStart: key,
    records: grouped[key],
    expanded: false
  }));
}
  // LOGOUT

  logout() {
    this.authService.logut();
    this.router.navigate(['/login']);
  }
}

function bp(value: any, index: number, array: any[]): string {
  throw new Error('Function not implemented.');
}
<div class="container" *ngIf="profile">

  <!-- PROFILE CARD -->
  <div class="card">
    <h2>Welcome {{ profile.name }}</h2>

    <p><strong>Age:</strong> {{ profile.age }}</p>
    <p><strong>BMI:</strong> {{ profile.bmi | number:'1.1-2' }}</p>
    <p><strong>Lifestyle:</strong> {{ profile.lifestyle }}</p>
    <p><strong>Blood Group:</strong> {{ profile.bloodGroup }}</p>

    <h4>Known Diseases</h4>
    <ul *ngIf="profile.knownDiseases?.length > 0; else noDiseases">
      <li *ngFor="let disease of profile.knownDiseases">
        {{ disease }}
      </li>
    </ul>

    <ng-template #noDiseases>
      <p>No known diseases</p>
    </ng-template>
  </div>

  <!-- ADDITIONAL INFO -->
  <div class="card" *ngIf="additionalInfos?.length > 0">
    <h3>Additional Information</h3>

    <div *ngFor="let info of additionalInfos">
      <p><strong>Emergency Contact:</strong> {{ info.emergency_contact }}</p>
      <p><strong>Allergies:</strong> {{ info.allergies }}</p>
      <p><strong>Notes:</strong> {{ info.medical_notes }}</p>
      <hr>
    </div>
  </div>

  <!-- Daily Blood Pressure -->
  <div class="card">

  <h3>🩺 Blood Pressure Tracker</h3>

  <!-- ================= CURRENT WEEK ================= -->
  <div *ngIf="currentWeekBP.length > 0">

    <h4>Current Week</h4>

    <table class="bp-table">
      <tr>
        <th>Metric</th>
        <th *ngFor="let bp of currentWeekBP">
          {{ bp.recorded_at | date:'shortDate' }}
        </th>
      </tr>

      <tr>
        <td><strong>Systolic</strong></td>
        <td *ngFor="let bp of currentWeekBP"
            [ngClass]="getBPClass(bp.systolic, bp.diastolic)">
          {{ bp.systolic }}
        </td>
      </tr>

      <tr>
        <td><strong>Diastolic</strong></td>
        <td *ngFor="let bp of currentWeekBP"
            [ngClass]="getBPClass(bp.systolic, bp.diastolic)">
          {{ bp.diastolic }}
        </td>
      </tr>

      <tr>
        <td><strong>Pulse</strong></td>
        <td *ngFor="let bp of currentWeekBP">
          {{ bp.pulse || '-' }}
        </td>
      </tr>
    </table>

  </div>

  <!-- ================= PREVIOUS WEEKS ================= -->

  <div *ngIf="previousWeeks.length > 0">

    <h4 style="margin-top: 30px;">Previous History</h4>

    <div *ngFor="let week of previousWeeks" class="week-section">

      <div class="week-header"
           (click)="week.expanded = !week.expanded">

        📅 Week of {{ week.weekStart }}
        <span>
          {{ week.expanded ? '▲' : '▼' }}
        </span>

      </div>

      <div *ngIf="week.expanded">

        <table class="bp-table">

          <tr>
            <th>Metric</th>
            <th *ngFor="let bp of week.records">
              {{ bp.recorded_at | date:'shortDate' }}
            </th>
          </tr>

          <tr>
            <td><strong>Systolic</strong></td>
            <td *ngFor="let bp of week.records">
              {{ bp.systolic }}
            </td>
          </tr>

          <tr>
            <td><strong>Diastolic</strong></td>
            <td *ngFor="let bp of week.records">
              {{ bp.diastolic }}
            </td>
          </tr>

          <tr>
            <td><strong>Pulse</strong></td>
            <td *ngFor="let bp of week.records">
              {{ bp.pulse || '-' }}
            </td>
          </tr>

        </table>

      </div>

    </div>

  </div>

</div>

  <!-- HEALTH SCORE -->
  <div class="card">
    <h3>Health Score</h3>
    <div class="progress">
      <div class="progress-bar" [style.width.%]="profile.healthScore" [ngStyle]="{
          'background-color': profile.healthScore >= 80 ? '#4caf50' :
                              profile.healthScore >= 60 ? '#ffc107' :
                              '#f44336'
        }">
        {{ profile.healthScore }}%
      </div>
    </div>
  </div>

  <!-- AI PLAN -->
  <div class="card">
    <h3>AI Diet & Workout Plan</h3>

    <button (click)="getPlan()">Generate Plan</button>

    <div *ngIf="aiPlan" class="ai-output-grid">

      <!-- MEAL PLAN -->
      <div class="plan-card">
        <h4>Meal Plan</h4>
        <ul>
          <li *ngFor="let meal of aiPlan.mealPlan">
            <strong>{{ meal.title }}</strong>
            <br>
            ⏱ {{ meal.readyInMinutes }} mins
            <br>
            <a [href]="meal.sourceUrl" target="_blank">View Recipe</a>
          </li>
        </ul>
      </div>

      <!-- FOODS TO AVOID -->
      <div class="plan-card" *ngIf="aiPlan.avoidFoods?.length">
        <h4>Foods to Avoid</h4>
        <ul>
          <li *ngFor="let item of aiPlan.avoidFoods">
            {{ item }}
          </li>
        </ul>
      </div>

      <div class="plan-card">
        <h4>Workout Plan</h4>

        <div *ngFor="let exercise of aiPlan?.workoutPlan" class="exercise-item">
          <strong>{{ exercise?.name }}</strong>

          <div [innerHTML]="exercise.description"></div>
        </div>
      </div>

      <!-- HEALTH INSIGHTS -->
      <div class="plan-card">
        <h4>Health Insights</h4>
        <ul>
          <li *ngFor="let insight of aiPlan.healthInsights">
            {{ insight }}
          </li>
        </ul>
      </div>

    </div>
  </div>

  <!-- REMINDER -->
  <div class="card">
    <h3>Medicine Reminder</h3>

    <div class="reminder-container">
      <input [(ngModel)]="medicineName" placeholder="Medicine Name">
      <input type="time" [(ngModel)]="medicineTime">
      <button (click)="setReminder()">Add</button>
    </div>

    <div class="reminder-list" *ngIf="reminders.length > 0">

      <div class="reminder-item" *ngFor="let r of reminders; let i = index">

        <!-- NORMAL VIEW -->
        <div *ngIf="!r.editing" class="reminder-view">
          <div class="reminder-info">
            <span class="reminder-name">{{ r.name }}</span>
            <span class="reminder-time">{{ r.time }}</span>
          </div>

          <div class="reminder-actions">
            <button class="edit-btn" (click)="editReminder(i)">Edit</button>
            <button class="delete-btn" (click)="deleteReminder(i)">✕</button>
          </div>
        </div>

        <!-- EDIT MODE -->
        <div *ngIf="r.editing" class="reminder-edit">
          <input [(ngModel)]="r.name">
          <input type="time" [(ngModel)]="r.time">

          <button class="save-btn" (click)="saveReminder(i)">Save</button>
          <button class="cancel-btn" (click)="cancelEdit(i)">Cancel</button>
        </div>

      </div>

    </div>
  </div>

  <button class="logout-btn" (click)="logout()">Logout</button>

</div>
